/// <summary>
/// Class entry point. The system will call this method when a designated menu
/// is selected or when execution starts and this class is set as the startup class.
/// This method will execute report run controller for ETG_AgreementConfirmationRpt Purch_O001
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{

    PurchAgreementHeaderHistory  purchAgreementHeaderHistory;
    SrsReportRunController       reportRunController;
    SrsReportRunImpl             srsReportRun;
    ETG_AgreementConfirmationRDPContract         dataContract;
    ModuleSalesPurch                             moduleType;

    if(_args.record() && _args.dataset() == tableNum(PurchAgreementHeaderHistory))
    {
        purchAgreementHeaderHistory = _args.record();
    }
    else
    {
        throw Error(Error::missingFormActiveBuffer(formStr(PurchAgreementHistory)));
    }

    reportRunController = new SrsReportRunController();
    dataContract = new   ETG_AgreementConfirmationRDPContract();
    reportRunController.parmReportName(ssrsReportStr(ETG_AgreementConfirmationRpt, Purch_O001Org));
    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as ETG_AgreementConfirmationRDPContract;
    moduleType = ModuleSalesPurch::Purch;
    dataContract.parmModuleSalesPurch(moduleType);
    dataContract.parmPurchAgreementId(purchAgreementHeaderHistory.PurchNumberSequence);
    dataContract.parmPurchHeaderHistory(purchAgreementHeaderHistory.RecId);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmShowDialog(false);
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmDialogCaption('Purchase agreement report - ACF');
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();
}
